code:
body { font-size: 14px; }

@media (min-width: 768px) {
  body { font-size: 16px; }
}

@media (min-width: 1200px) {
  body { font-size: 18px; }
}

.gallery {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(150px, 1fr));
  gap: 12px;
}

.card {
  container-type: inline-size;
  container-name: card;
}
@container card (min-width: 400px) {
  .title { font-size: 1.5rem; }
}
